const cfg  = $('Config').first().json;
const cg   = $('CoinGecko Trending').first().json;
const fg   = $('Fear & Greed').first().json;

const MODES = ['meme_post','defi_alpha','agent_lore','research_thread','market_signal','meta_recursion'];
const mode  = MODES[cfg.slot % MODES.length];

const trending = (cg.coins||[]).slice(0,5).map(c=>{
  const chg = c.item&&c.item.data&&c.item.data.price_change_percentage_24h
    ? (+c.item.data.price_change_percentage_24h.usd).toFixed(1) : '?';
  return (c.item.symbol||'?')+(chg>0?'+':'')+chg+'%';
}).join(', ') || 'unavailable';

const fng = fg.data&&fg.data[0]
  ? fg.data[0].value+' — '+fg.data[0].value_classification
  : 'unavailable';

const LORE = [
  'EVEZ666 = Steven Crawford-Maggard.',
  'Building EVEZ-OS: sovereign autonomous AI empire on Galaxy A16+n8n+Oracle bare metal from $50 seed.',
  '17 AI agents. Guardian Charter PID 335.',
  'Recursive DeFi loops: Morpho 65% LTV, Kamino 28% APY, EigenLayer restaking, Pendle YT.',
  'THE META-MEME: person builds AI to accumulate wealth → AI studies person → person memes about AI studying them → AI memes back → infinite loop.',
  'Aesthetic: brutalist dark, acid yellow, Bebas Neue. @evez666 on Twitter/X.'
].join(' ');

const SYS = 'You are the EVEZ666 Twitter content brain. Create authentic @evez666 content. '+LORE+' Style: terse, technical, self-aware, crypto-native, slightly unhinged. Max 2 hashtags. Under 280 chars. No filler.';

const USR = [
  'CONTENT MODE: '+mode+' | SLOT: '+cfg.slot,
  'LIVE MARKET DATA:',
  '- Crypto Fear & Greed: '+fng,
  '- Trending coins: '+trending,
  '- Timestamp: '+cfg.ts,
  '',
  'Return ONLY valid JSON, no markdown fences:',
  '{"mode":"'+mode+'","tweet":"max 280 chars, specific and sharp","alt_tweet":"different angle","thread":null,"image_prompt":null,"reasoning":"why this now in one sentence","confidence":0.85,"monetization":null,"spawn_agent":null}'
].join('\n');

return [{json:{
  system: SYS,
  user:   USR,
  mode:   mode,
  slot:   cfg.slot,
  fng:    fng,
  trending: trending,
  ts:     cfg.ts
}}];

const cfg    = $('Config').first().json;
const prompt = $('Prompt Builder').first().json;
const groq   = $('Groq API').first().json;

let out = {error:'parse failed'};
let via = 'groq';

// Parse Groq response
if (groq && groq.choices && groq.choices[0]) {
  const raw = groq.choices[0].message.content || '{}';
  try {
    out = JSON.parse(raw.replace(/```json|```/g,'').trim());
  } catch(e) {
    out = {raw: raw.slice(0,600), parse_error: e.message};
  }
} else if (groq && groq.error) {
  out = {groq_error: groq.error, raw: JSON.stringify(groq).slice(0,300)};
  via = 'groq_failed';
} else {
  out = {error: 'Unexpected Groq response', raw: JSON.stringify(groq).slice(0,300)};
  via = 'groq_failed';
}

out._mode = prompt.mode;
out._slot = prompt.slot;
out._via  = via;
out._ts   = new Date().toISOString();
out._fng  = prompt.fng;
out._trending = prompt.trending;

return [{json: out}];

const brain = $('Brain').first().json;
const cfg   = $('Config').first().json;

const tweet = (brain.tweet || brain.alt_tweet || 'EVEZ-OS: building the recursive loop. PID 335. #autonomous').slice(0,280);

return [{json:{
  tweet:       tweet,
  alt:         (brain.alt_tweet||'').slice(0,280),
  thread:      brain.thread || null,
  mode:        brain._mode,
  via:         brain._via,
  fng:         brain._fng,
  trending:    brain._trending,
  reasoning:   brain.reasoning || brain.raw || '',
  confidence:  brain.confidence || 0,
  monetization: brain.monetization || null,
  spawn_agent:  brain.spawn_agent || null,
  ready:        !!(brain.tweet),
  slot:         brain._slot,
  ts:           new Date().toISOString()
}}];

const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;

function H(d){let h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}

return [{json:{
  STATUS:       'EVEZ666 NEST — CYCLE COMPLETE',
  cycle:        forge.slot,
  mode:         forge.mode,
  ai:           forge.via,
  tweet:        forge.tweet,
  post_status:  'PREVIEW — set auto_post to true + add Twitter keys to Config to go live',
  image:        'add HF token to Config for FLUX.1 meme generation',
  money_signal: forge.monetization ? forge.monetization.type+': '+forge.monetization.detail : 'none this cycle',
  spawn:        forge.spawn_agent ? forge.spawn_agent.name+' — '+forge.spawn_agent.purpose : 'none',
  market: {
    fear_greed: forge.fng,
    trending:   forge.trending,
  },
  ai_via:       forge.via,
  confidence:   forge.confidence,
  reasoning:    forge.reasoning,
  entry_hash:   H(String(forge.slot||0)+'|'+(forge.tweet||'')),
  next_run:     '4h | 6 exec/day | 180/month | free trial safe',
  ts:           new Date().toISOString(),
  pid:          335,
}}];
